  var as = ass.getActiveSheet();
  var today = new Date();
  today.setHours(0,0,0,0);
  var datesRange = as.getRange(1, 1, 1, as.getLastColumn());
  for (var column = 1; column <= datesRange.getNumColumns(); column++) {
